import React, { useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Typed } from 'react-typed';
import { FiArrowRight, FiDownload, FiGithub, FiLinkedin } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const c = { hidden:{opacity:0}, visible:{opacity:1, transition:{staggerChildren:0.1, delayChildren:0.2}} };
const i = { hidden:{y:24,opacity:0}, visible:{y:0,opacity:1,transition:{type:'spring',stiffness:80,damping:16}} };

const Hero = () => {
    const { theme } = useTheme();
    const el = useRef(null);

    useEffect(() => {
        if (!el.current) return;
        const t = new Typed(el.current, {
            strings: ['Web Developer', 'Laravel Developer', 'React Developer', 'Full Stack Dev'],
            typeSpeed: 55, backSpeed: 32, backDelay: 2000, loop: true,
        });
        return () => t.destroy();
    }, []);

    return (
        <section id="home" style={{
            minHeight: '100vh', display: 'flex', alignItems: 'center',
            padding: 'clamp(90px,14vh,130px) 0 clamp(48px,7vh,80px)',
            position: 'relative', overflow: 'hidden',
        }}>
            {/* BG ambient blobs */}
            <div style={{
                position:'absolute', width:560, height:560, borderRadius:'50%',
                background:'radial-gradient(circle,rgba(99,102,241,0.11) 0%,transparent 65%)',
                top:'-12%', left:'-14%', pointerEvents:'none', filter:'blur(55px)', zIndex:0,
            }}/>
            <div style={{
                position:'absolute', width:420, height:420, borderRadius:'50%',
                background:'radial-gradient(circle,rgba(34,211,238,0.07) 0%,transparent 65%)',
                bottom:'-8%', right:'-8%', pointerEvents:'none', filter:'blur(50px)', zIndex:0,
            }}/>

            {/* Grid lines */}
            <div style={{
                position:'absolute', inset:0, zIndex:0, pointerEvents:'none',
                backgroundImage: [
                    'linear-gradient(rgba(99,102,241,0.04) 1px, transparent 1px)',
                    'linear-gradient(90deg, rgba(99,102,241,0.04) 1px, transparent 1px)',
                ].join(', '),
                backgroundSize: '64px 64px',
                maskImage: 'radial-gradient(ellipse 85% 85% at 50% 50%, black 20%, transparent 100%)',
                WebkitMaskImage: 'radial-gradient(ellipse 85% 85% at 50% 50%, black 20%, transparent 100%)',
            }}/>

            <motion.div
                initial="hidden" animate="visible" variants={c}
                style={{ maxWidth:1200, margin:'0 auto', padding:'0 24px', width:'100%', position:'relative', zIndex:1 }}
            >
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(0, 1fr))',
                    gap: 'clamp(32px, 5vw, 64px)',
                    alignItems: 'center',
                }}>
                    {/* LEFT */}
                    <div style={{ minWidth:0 }}>
                        {/* Badge */}
                        <motion.div variants={i} style={{ marginBottom:18 }}>
                            <span style={{
                                display:'inline-flex', alignItems:'center', gap:8,
                                padding:'5px 14px', borderRadius:100,
                                background:'rgba(99,102,241,0.1)',
                                border:'1px solid rgba(99,102,241,0.22)',
                                fontSize:11, fontWeight:700, color:'#a5b4fc',
                                letterSpacing:1.8, textTransform:'uppercase',
                            }}>
                                <span style={{ width:6, height:6, borderRadius:'50%', background:'#22d3ee', boxShadow:'0 0 8px #22d3ee', display:'inline-block' }}/>
                                Open to Work
                            </span>
                        </motion.div>

                        {/* Heading */}
                        <motion.h1 variants={i} style={{
                            fontFamily: 'Outfit, sans-serif',
                            fontSize: 'clamp(2.4rem, 7vw, 4.5rem)',
                            fontWeight: 900, lineHeight: 1.05,
                            color: theme.textPrimary,
                            marginBottom: 14, letterSpacing: '-2px',
                        }}>
                            Halo, saya<br/>
                            <span style={{
                                background: 'linear-gradient(135deg, #a5b4fc 0%, #6366f1 45%, #22d3ee 100%)',
                                WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
                            }}>Bara Kusuma</span>
                        </motion.h1>

                        {/* Typed */}
                        <motion.div variants={i} style={{
                            fontSize: 'clamp(1rem, 2.5vw, 1.3rem)', fontWeight:500,
                            marginBottom: 20, minHeight: 34,
                            display: 'flex', alignItems: 'center', gap:8, flexWrap:'wrap',
                            color: theme.textSecondary,
                        }}>
                            Seorang&nbsp;
                            <span style={{
                                background:'linear-gradient(135deg,#22d3ee,#6366f1)',
                                WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
                                fontWeight:700,
                            }}>
                                <span ref={el}/>
                            </span>
                        </motion.div>

                        {/* Description */}
                        <motion.p variants={i} style={{
                            fontSize: 'clamp(14px,1.8vw,15.5px)', lineHeight:1.8,
                            color: theme.textSecondary, marginBottom: 28, maxWidth: 430,
                        }}>
                            Pengembang web yang senang membangun produk digital yang cepat, bersih, dan menyenangkan untuk digunakan.
                        </motion.p>

                        {/* CTAs */}
                        <motion.div variants={i} style={{ display:'flex', flexWrap:'wrap', gap:12, marginBottom:28 }}>
                            <a href="#contact"
                                onClick={e => { e.preventDefault(); document.getElementById('contact')?.scrollIntoView({behavior:'smooth'}); }}
                                className="btn-p">
                                Hubungi Saya <FiArrowRight size={15}/>
                            </a>
                            <a href={process.env.PUBLIC_URL + '/CV - Bara Kusuma.pdf'} download className="btn-s">
                                <FiDownload size={14}/> Unduh CV
                            </a>
                        </motion.div>

                        {/* Socials */}
                        <motion.div variants={i} style={{ display:'flex', alignItems:'center', gap:10 }}>
                            <span style={{ fontSize:11, color:theme.textMuted, fontWeight:600, letterSpacing:1.5, textTransform:'uppercase' }}>Social</span>
                            <div style={{ width:1, height:14, background:theme.border }}/>
                            {[
                                { href:'https://github.com/BekaGensss', icon:<FiGithub size={16}/>, label:'GitHub' },
                                { href:'https://id.linkedin.com/in/bara-kusuma-707067294', icon:<FiLinkedin size={16}/>, label:'LinkedIn' },
                            ].map(s => (
                                <a key={s.label} href={s.href} target="_blank" rel="noopener noreferrer" aria-label={s.label}
                                    style={{
                                        width:36, height:36, borderRadius:9,
                                        background:theme.bgCard, border:`1px solid ${theme.border}`,
                                        display:'flex', alignItems:'center', justifyContent:'center',
                                        color:theme.textMuted, textDecoration:'none', transition:'all 0.22s ease',
                                    }}
                                    onMouseEnter={e=>{ e.currentTarget.style.background=theme.accentBg; e.currentTarget.style.borderColor=theme.accentBorder; e.currentTarget.style.color=theme.accentText; e.currentTarget.style.transform='translateY(-2px)'; }}
                                    onMouseLeave={e=>{ e.currentTarget.style.background=theme.bgCard; e.currentTarget.style.borderColor=theme.border; e.currentTarget.style.color=theme.textMuted; e.currentTarget.style.transform='translateY(0)'; }}
                                >{s.icon}</a>
                            ))}
                        </motion.div>
                    </div>

                    {/* RIGHT: Photo */}
                    <motion.div variants={i} style={{ display:'flex', justifyContent:'center', alignItems:'center' }}>
                        <div className="float-anim">
                            <div className="profile-wrap">
                                <img
                                    src={process.env.PUBLIC_URL + '/profile.jpg'}
                                    alt="Bara Kusuma"
                                    className="profile-img"
                                    style={{
                                        width: 'clamp(175px, 27vw, 268px)',
                                        height: 'clamp(175px, 27vw, 268px)',
                                        objectFit: 'cover',
                                    }}
                                />
                            </div>
                        </div>
                    </motion.div>
                </div>

                {/* Scroll hint */}
                <motion.div
                    initial={{opacity:0}} animate={{opacity:0.45}} transition={{delay:2.5}}
                    style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:7, marginTop:'clamp(32px,5vw,56px)' }}
                >
                    <span style={{ fontSize:10, color:theme.textMuted, letterSpacing:3, textTransform:'uppercase', fontWeight:600 }}>Scroll</span>
                    <div style={{ width:20, height:30, border:`1.5px solid ${theme.accentBorder}`, borderRadius:10, display:'flex', justifyContent:'center', padding:3 }}>
                        <motion.div animate={{y:[0,9,0]}} transition={{repeat:Infinity, duration:1.4, ease:'easeInOut'}}
                            style={{ width:3, height:6, borderRadius:2, background:theme.accent }}/>
                    </div>
                </motion.div>
            </motion.div>
        </section>
    );
};

export default Hero;