import React, { useState, useEffect } from 'react';
import { FiChevronUp, FiGithub, FiLinkedin, FiHeart } from 'react-icons/fi';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from '../ThemeContext';

const navLinks = [
    {href:'#home',label:'Home'},{href:'#about',label:'Tentang'},
    {href:'#projects',label:'Proyek'},{href:'#contact',label:'Kontak'},
];
const socials = [
    {href:'https://github.com/BekaGensss',                    icon:<FiGithub size={16}/>,   label:'GitHub'},
    {href:'https://id.linkedin.com/in/bara-kusuma-707067294', icon:<FiLinkedin size={16}/>, label:'LinkedIn'},
];

const Footer = () => {
    const { theme } = useTheme();
    const [show, setShow] = useState(false);
    useEffect(() => {
        const fn = () => setShow(window.scrollY > 400);
        window.addEventListener('scroll', fn, {passive:true});
        return () => window.removeEventListener('scroll', fn);
    }, []);
    const top = () => window.scrollTo({top:0,behavior:'smooth'});

    return (
        <footer style={{ background:theme.navBg, borderTop:`1px solid ${theme.border}`, padding:'36px 0 24px', position:'relative' }}>
            <div style={{ maxWidth:1200, margin:'0 auto', padding:'0 24px' }}>
                {/* Top */}
                <div style={{
                    display:'flex', flexWrap:'wrap', justifyContent:'space-between',
                    alignItems:'center', gap:18, marginBottom:24,
                    paddingBottom:20, borderBottom:`1px solid ${theme.divider}`,
                }}>
                    {/* Brand */}
                    <div>
                        <div style={{ display:'flex', alignItems:'center', gap:9, marginBottom:8 }}>
                            <div style={{
                                width:30,height:30,borderRadius:9,
                                background:'linear-gradient(135deg,#6366f1,#4f46e5)',
                                display:'flex',alignItems:'center',justifyContent:'center',
                                fontFamily:'Outfit,sans-serif',fontWeight:900,fontSize:14,color:'#fff',
                                boxShadow:'0 0 16px rgba(99,102,241,0.35)',
                            }}>B</div>
                            <span style={{ fontFamily:'Outfit,sans-serif',fontWeight:700,fontSize:16,color:theme.textPrimary }}>
                                Bara<span style={{color:theme.accentText}}>.dev</span>
                            </span>
                        </div>
                        <p style={{ fontSize:13,color:theme.textSecondary,maxWidth:200,lineHeight:1.6 }}>
                            Membangun pengalaman digital yang modern.
                        </p>
                    </div>

                    {/* Nav */}
                    <nav aria-label="Footer nav">
                        <div style={{ display:'flex', flexWrap:'wrap', gap:'5px 18px', justifyContent:'center' }}>
                            {navLinks.map(l=>(
                                <a key={l.href} href={l.href}
                                    onClick={e=>{ e.preventDefault(); document.querySelector(l.href)?.scrollIntoView({behavior:'smooth'}); }}
                                    style={{ fontSize:13.5,fontWeight:500,color:theme.textSecondary,textDecoration:'none',transition:'color 0.22s' }}
                                    onMouseEnter={e=>e.currentTarget.style.color=theme.accentText}
                                    onMouseLeave={e=>e.currentTarget.style.color=theme.textSecondary}
                                >{l.label}</a>
                            ))}
                        </div>
                    </nav>

                    {/* Socials */}
                    <div style={{ display:'flex', gap:8 }}>
                        {socials.map(s=>(
                            <a key={s.label} href={s.href} target="_blank" rel="noopener noreferrer" aria-label={s.label}
                                style={{
                                    width:34,height:34,borderRadius:9,
                                    background:theme.bgCard,border:`1px solid ${theme.border}`,
                                    display:'flex',alignItems:'center',justifyContent:'center',
                                    color:theme.textMuted,textDecoration:'none',transition:'all 0.22s ease',
                                }}
                                onMouseEnter={e=>{ e.currentTarget.style.background=theme.accentBg; e.currentTarget.style.borderColor=theme.accentBorder; e.currentTarget.style.color=theme.accentText; e.currentTarget.style.transform='translateY(-2px)'; }}
                                onMouseLeave={e=>{ e.currentTarget.style.background=theme.bgCard; e.currentTarget.style.borderColor=theme.border; e.currentTarget.style.color=theme.textMuted; e.currentTarget.style.transform='translateY(0)'; }}
                            >{s.icon}</a>
                        ))}
                    </div>
                </div>

                {/* Bottom */}
                <div style={{ display:'flex', flexWrap:'wrap', justifyContent:'space-between', alignItems:'center', gap:10 }}>
                    <p style={{ fontSize:12.5,color:theme.textMuted }}>&copy; {new Date().getFullYear()} Bara Kusuma. Semua hak dilindungi.</p>
                    <p style={{ fontSize:12.5,color:theme.textMuted,display:'flex',alignItems:'center',gap:5 }}>
                        Dibuat dengan <FiHeart size={11} style={{color:'#6366f1'}}/> React
                    </p>
                </div>
            </div>

            {/* Scroll top */}
            <AnimatePresence>
                {show && (
                    <motion.button key="stb"
                        initial={{scale:0,opacity:0}} animate={{scale:1,opacity:1}} exit={{scale:0,opacity:0}}
                        onClick={top} aria-label="Ke atas"
                        style={{
                            position:'fixed', bottom:22, right:20,
                            width:40,height:40,borderRadius:12,
                            background:'linear-gradient(135deg,#6366f1,#4f46e5)',
                            border:'none',display:'flex',alignItems:'center',justifyContent:'center',
                            color:'white',cursor:'pointer',zIndex:50,
                            boxShadow:'0 6px 20px rgba(99,102,241,0.5)',
                        }}
                        whileHover={{y:-3,boxShadow:'0 10px 28px rgba(99,102,241,0.6)'}}
                        whileTap={{scale:0.9}}
                    >
                        <FiChevronUp size={20}/>
                    </motion.button>
                )}
            </AnimatePresence>
        </footer>
    );
};

export default Footer;