import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiSun, FiMoon, FiMenu, FiX } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const links = [
    { href: '#home',     label: 'Home'    },
    { href: '#about',    label: 'Tentang' },
    { href: '#projects', label: 'Proyek'  },
    { href: '#github',   label: 'GitHub'  },
    { href: '#contact',  label: 'Kontak'  },
];

const scrollTo = (id, cb) => {
    const el = document.getElementById(id.replace('#', ''));
    if (el) window.scrollTo({ top: el.getBoundingClientRect().top + window.pageYOffset - 80, behavior: 'smooth' });
    if (cb) cb();
};

const Navbar = () => {
    const { isDark, theme, toggleTheme } = useTheme();
    const [open,    setOpen]    = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [active,  setActive]  = useState('home');

    useEffect(() => {
        const onScroll = () => {
            setScrolled(window.scrollY > 40);
            ['home','about','projects','github','contact'].forEach(id => {
                const el = document.getElementById(id);
                if (el && window.scrollY >= el.offsetTop - 130) setActive(id);
            });
        };
        window.addEventListener('scroll', onScroll, { passive: true });
        return () => window.removeEventListener('scroll', onScroll);
    }, []);

    const close = () => setOpen(false);

    return (
        <>
            {/* Desktop: floating centered pill */}
            <motion.header
                initial={{ y: -70, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.5, ease: 'easeOut' }}
                style={{
                    position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
                    display: 'flex', justifyContent: 'space-between',
                    alignItems: 'center', padding: '0 24px', height: 64,
                    background: scrolled ? theme.navBg : 'transparent',
                    backdropFilter: scrolled ? 'blur(24px)' : 'none',
                    WebkitBackdropFilter: scrolled ? 'blur(24px)' : 'none',
                    borderBottom: scrolled ? `1px solid ${theme.border}` : '1px solid transparent',
                    transition: 'all 0.35s ease',
                }}
            >
                {/* Logo */}
                <a href="#home" onClick={e => { e.preventDefault(); scrollTo('#home'); }}
                    style={{ display: 'flex', alignItems: 'center', gap: 9, textDecoration: 'none', flexShrink: 0 }}>
                    <div style={{
                        width: 34, height: 34, borderRadius: 10,
                        background: 'linear-gradient(135deg, #6366f1, #4f46e5)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontFamily: 'Outfit, sans-serif', fontWeight: 900, fontSize: 16,
                        color: '#fff', boxShadow: '0 0 20px rgba(99,102,241,0.4)',
                        letterSpacing: '-0.5px',
                    }}>B</div>
                    <span style={{
                        fontFamily: 'Outfit, sans-serif', fontWeight: 700, fontSize: 17,
                        color: theme.textPrimary, letterSpacing: '-0.3px',
                    }}>
                        Bara<span style={{ color: theme.accentText }}>.dev</span>
                    </span>
                </a>

                {/* Desktop nav - floating pill */}
                <div className="nav-desk" style={{
                    display: 'flex', alignItems: 'center',
                    background: 'rgba(12,12,22,0.75)',
                    backdropFilter: 'blur(20px)',
                    WebkitBackdropFilter: 'blur(20px)',
                    border: `1px solid ${theme.border}`,
                    borderRadius: 100, padding: '4px 6px', gap: 2,
                }}>
                    {links.map(l => {
                        const isAct = active === l.href.replace('#', '');
                        return (
                            <a key={l.href} href={l.href}
                                onClick={e => { e.preventDefault(); scrollTo(l.href); }}
                                style={{
                                    padding: '6px 16px', borderRadius: 100,
                                    fontSize: 13.5, fontWeight: 500,
                                    color: isAct ? '#fff' : theme.textSecondary,
                                    background: isAct ? 'linear-gradient(135deg,#6366f1,#4f46e5)' : 'transparent',
                                    textDecoration: 'none', cursor: 'pointer',
                                    transition: 'all 0.22s ease', whiteSpace: 'nowrap',
                                    boxShadow: isAct ? '0 4px 14px rgba(99,102,241,0.4)' : 'none',
                                }}
                                onMouseEnter={e => { if (!isAct) { e.currentTarget.style.color = theme.accentText; e.currentTarget.style.background = theme.accentBg; } }}
                                onMouseLeave={e => { if (!isAct) { e.currentTarget.style.color = theme.textSecondary; e.currentTarget.style.background = 'transparent'; } }}
                            >{l.label}</a>
                        );
                    })}
                </div>

                {/* Right: theme + hire */}
                <div className="nav-desk" style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <button onClick={toggleTheme} aria-label="Toggle theme"
                        style={{
                            width: 36, height: 36, borderRadius: 10,
                            background: theme.accentBg, border: `1px solid ${theme.border}`,
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: theme.accentText, cursor: 'pointer', transition: 'all 0.25s ease',
                        }}
                        onMouseEnter={e => { e.currentTarget.style.transform = 'rotate(18deg) scale(1.05)'; }}
                        onMouseLeave={e => { e.currentTarget.style.transform = 'rotate(0deg) scale(1)'; }}
                    >
                        {isDark ? <FiSun size={15} /> : <FiMoon size={15} />}
                    </button>
                    <a href="#contact" onClick={e => { e.preventDefault(); scrollTo('#contact'); }}
                        className="btn-p" style={{ padding: '9px 20px', borderRadius: 10, fontSize: 13.5 }}>
                        Hire Me
                    </a>
                </div>

                {/* Mobile buttons */}
                <div className="nav-mob" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <button onClick={toggleTheme} aria-label="Toggle theme"
                        style={{
                            width: 34, height: 34, borderRadius: 9, border: `1px solid ${theme.border}`,
                            background: theme.accentBg, cursor: 'pointer',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: theme.accentText,
                        }}>
                        {isDark ? <FiSun size={14} /> : <FiMoon size={14} />}
                    </button>
                    <button onClick={() => setOpen(o => !o)} aria-label="Menu"
                        style={{
                            width: 34, height: 34, borderRadius: 9,
                            border: `1px solid ${theme.accentBorder}`,
                            background: theme.accentBg, cursor: 'pointer',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: theme.accentText,
                        }}>
                        {open ? <FiX size={16} /> : <FiMenu size={15} />}
                    </button>
                </div>
            </motion.header>

            {/* Mobile drawer */}
            <AnimatePresence>
                {open && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2 }}
                        style={{
                            position: 'fixed', top: 64, left: 0, right: 0, zIndex: 999,
                            background: theme.navBg, backdropFilter: 'blur(24px)',
                            borderBottom: `1px solid ${theme.border}`,
                            padding: '12px 20px 18px',
                        }}
                    >
                        {links.map(l => {
                            const isAct = active === l.href.replace('#', '');
                            return (
                                <a key={l.href} href={l.href}
                                    onClick={e => { e.preventDefault(); scrollTo(l.href, close); }}
                                    style={{
                                        display: 'block', padding: '12px 16px', borderRadius: 12, marginBottom: 4,
                                        fontSize: 14, fontWeight: 500,
                                        color: isAct ? theme.accentText : theme.textSecondary,
                                        background: isAct ? theme.accentBg : 'transparent',
                                        border: `1px solid ${isAct ? theme.accentBorder : 'transparent'}`,
                                        textDecoration: 'none', cursor: 'pointer',
                                        transition: 'all 0.2s ease',
                                    }}
                                >{l.label}</a>
                            );
                        })}
                        <a href="#contact" onClick={e => { e.preventDefault(); scrollTo('#contact', close); }}
                            className="btn-p" style={{ display: 'block', textAlign: 'center', marginTop: 8, borderRadius: 12, width: '100%' }}>
                            Hire Me
                        </a>
                    </motion.div>
                )}
            </AnimatePresence>

            <style>{`
                .nav-desk { display: none !important; }
                .nav-mob  { display: flex !important; }
                @media (min-width: 768px) {
                    .nav-desk { display: flex !important; }
                    .nav-mob  { display: none !important; }
                }
            `}</style>
        </>
    );
};

export default Navbar;